const allItems = $input.all();
if (!allItems || allItems.length === 0) {
  return [{ json: { valid: false, errors: ['No items received'], ext: null, filename: null, datasetId: null, binaryKey: null } }];
}
const item = allItems[0];
const binary = item.binary || {};
if (Object.keys(binary).length === 0) {
  return [{ json: { valid: false, errors: ['No file found in request - ensure Content-Type: multipart/form-data'], ext: null, filename: null, datasetId: null, binaryKey: null } }];
}
const binaryKey = Object.keys(binary)[0];
const file = binary[binaryKey];
const filename = file.fileName || file.filename || 'upload';
const ext = filename.split('.').pop().toLowerCase();
const allowedExts = ['csv', 'xlsx', 'xls'];
const maxBytes = 10 * 1024 * 1024;
const errors = [];
if (!allowedExts.includes(ext)) {
  errors.push('File type .' + ext + ' not allowed. Use: csv, xlsx, xls');
}
if (file.fileSize && file.fileSize > maxBytes) {
  errors.push('File too large (max 10MB)');
}
const { randomUUID } = require('crypto');
const datasetId = randomUUID();
return [{ json: { valid: errors.length === 0, errors: errors, ext: ext, filename: filename, datasetId: datasetId, binaryKey: binaryKey }, binary: binary }];

const allItems = $input.all();
const rows = allItems.map(function(i) { return i.json; });
return [{ json: { hasRows: rows.length > 0, rowCount: rows.length, rows: rows } }];

const data = $input.first().json;
const rows = data.rows || [];
const columns = rows.length > 0 ? Object.keys(rows[0]) : [];
const nRows = rows.length;
const nCols = columns.length;
function isNumeric(v) {
  if (v === null || v === undefined || v === '') return false;
  const n = Number(v);
  return !isNaN(n) && isFinite(n);
}
function isDatetime(v) {
  if (typeof v !== 'string' || v.length < 5 || !isNaN(Number(v))) return false;
  return !isNaN(Date.parse(v));
}
const numericCols = [];
const categoricalCols = [];
const datetimeCols = [];
const profile = {};
for (var ci = 0; ci < columns.length; ci++) {
  const col = columns[ci];
  const vals = rows.map(function(r) { return r[col]; }).filter(function(v) { return v !== null && v !== undefined && v !== ''; });
  const allNum = vals.length > 0 && vals.every(isNumeric);
  const allDate = !allNum && vals.length > 0 && vals.every(isDatetime);
  const dtype = allNum ? 'numeric' : allDate ? 'datetime' : 'categorical';
  if (dtype === 'numeric') numericCols.push(col);
  else if (dtype === 'datetime') datetimeCols.push(col);
  else categoricalCols.push(col);
  const missing = rows.filter(function(r) { return r[col] === null || r[col] === undefined || r[col] === ''; }).length;
  const seen2 = {};
  vals.forEach(function(v) { seen2[String(v)] = true; });
  const uniqueVals = Object.keys(seen2);
  const topValues = dtype === 'categorical' ? uniqueVals.slice(0, 5) : [];
  profile[col] = { dtype: dtype, missing: missing, unique: uniqueVals.length, topValues: topValues };
}
const seen = {};
let duplicateCount = 0;
for (var ri = 0; ri < rows.length; ri++) {
  const key = JSON.stringify(rows[ri]);
  if (seen[key]) duplicateCount++;
  else seen[key] = true;
}
return [{ json: { rows: rows, nRows: nRows, nCols: nCols, numericCols: numericCols, categoricalCols: categoricalCols, datetimeCols: datetimeCols, profile: profile, duplicateCount: duplicateCount } }];

const data = $input.first().json;
let rows = data.rows || [];
let numericCols = (data.numericCols || []).slice();
let categoricalCols = (data.categoricalCols || []).slice();
let datetimeCols = (data.datetimeCols || []).slice();
const profile = data.profile || {};
const nCols = data.nCols || 0;
const duplicateCount = data.duplicateCount || 0;
function toSnake(s) {
  return String(s).toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '');
}
const colMap = {};
if (rows.length > 0) {
  Object.keys(rows[0]).forEach(function(col) { colMap[col] = toSnake(col); });
}
const renamedRows = rows.map(function(r) {
  const n = {};
  Object.keys(r).forEach(function(k) { n[colMap[k] || k] = r[k]; });
  return n;
});
function rename(k) { return colMap[k] || k; }
numericCols = numericCols.map(rename);
categoricalCols = categoricalCols.map(rename);
datetimeCols = datetimeCols.map(rename);
function median(arr) {
  const s = arr.slice().sort(function(a, b) { return a - b; });
  const m = Math.floor(s.length / 2);
  return s.length % 2 ? s[m] : (s[m - 1] + s[m]) / 2;
}
const medians = {};
for (var ni = 0; ni < numericCols.length; ni++) {
  const col = numericCols[ni];
  const vals = renamedRows.map(function(r) { return parseFloat(r[col]); }).filter(function(v) { return !isNaN(v); });
  medians[col] = vals.length ? median(vals) : 0;
}
const seen = {};
const cleanedRows = [];
for (var ri = 0; ri < renamedRows.length; ri++) {
  const row = renamedRows[ri];
  const r = Object.assign({}, row);
  numericCols.forEach(function(col) {
    if (r[col] === null || r[col] === undefined || r[col] === '') r[col] = medians[col];
    else r[col] = parseFloat(r[col]);
  });
  categoricalCols.forEach(function(col) {
    if (r[col] === null || r[col] === undefined || r[col] === '') r[col] = 'Unknown';
  });
  const key = JSON.stringify(r);
  if (!seen[key]) { seen[key] = true; cleanedRows.push(r); }
}
const outlierReport = {};
for (var oi = 0; oi < numericCols.length; oi++) {
  const col = numericCols[oi];
  const vals = cleanedRows.map(function(r) { return r[col]; }).filter(function(v) { return typeof v === 'number'; });
  if (vals.length === 0) {
    outlierReport[col] = { q1: 0, q3: 0, iqr: 0, lowerFence: 0, upperFence: 0, outlierCount: 0 };
    continue;
  }
  const s = vals.slice().sort(function(a, b) { return a - b; });
  const q1 = s[Math.floor(s.length * 0.25)] || 0;
  const q3 = s[Math.floor(s.length * 0.75)] || 0;
  const iqr = q3 - q1;
  const lo = q1 - 1.5 * iqr;
  const hi = q3 + 1.5 * iqr;
  const outlierCount = cleanedRows.filter(function(r) { return r[col] < lo || r[col] > hi; }).length;
  outlierReport[col] = { q1: q1, q3: q3, iqr: iqr, lowerFence: lo, upperFence: hi, outlierCount: outlierCount };
}
return [{ json: { cleanedRows: cleanedRows, columnRenameMap: colMap, outlierReport: outlierReport, numericCols: numericCols, categoricalCols: categoricalCols, datetimeCols: datetimeCols, profile: profile, nRows: cleanedRows.length, nCols: nCols, duplicateCount: duplicateCount } }];

const d = $input.first().json;
const cleanedRows = d.cleanedRows || [];
const numericCols = d.numericCols || [];
function calcStats(vals) {
  const n = vals.length;
  if (!n) return { count: 0, min: 0, max: 0, mean: 0, median: 0, std: 0, q1: 0, q3: 0 };
  const s = vals.slice().sort(function(a, b) { return a - b; });
  const sum = vals.reduce(function(a, b) { return a + b; }, 0);
  const mean = sum / n;
  const variance = vals.reduce(function(acc, v) { return acc + (v - mean) * (v - mean); }, 0) / n;
  const q1 = s[Math.floor(n * 0.25)] || 0;
  const q3 = s[Math.floor(n * 0.75)] || 0;
  const med = n % 2 ? s[Math.floor(n / 2)] : (s[n / 2 - 1] + s[n / 2]) / 2;
  return { count: n, min: s[0], max: s[n - 1], mean: +mean.toFixed(4), median: med, std: +Math.sqrt(variance).toFixed(4), q1: q1, q3: q3 };
}
const descriptiveStats = {};
for (var i = 0; i < numericCols.length; i++) {
  const col = numericCols[i];
  const vals = cleanedRows.map(function(r) { return r[col]; }).filter(function(v) { return typeof v === 'number'; });
  descriptiveStats[col] = calcStats(vals);
}
function pearson(xs, ys) {
  const n = xs.length;
  if (!n) return 0;
  const mx = xs.reduce(function(a, b) { return a + b; }, 0) / n;
  const my = ys.reduce(function(a, b) { return a + b; }, 0) / n;
  let num = 0, dx = 0, dy = 0;
  for (var j = 0; j < n; j++) {
    const a = xs[j] - mx, b = ys[j] - my;
    num += a * b; dx += a * a; dy += b * b;
  }
  return (dx && dy) ? +(num / Math.sqrt(dx * dy)).toFixed(4) : 0;
}
const correlationMatrix = {};
for (var ci = 0; ci < numericCols.length; ci++) {
  const c1 = numericCols[ci];
  correlationMatrix[c1] = {};
  const v1 = cleanedRows.map(function(r) { return r[c1]; }).filter(function(v) { return typeof v === 'number'; });
  for (var cj = 0; cj < numericCols.length; cj++) {
    const c2 = numericCols[cj];
    const v2 = cleanedRows.map(function(r) { return r[c2]; }).filter(function(v) { return typeof v === 'number'; });
    const len = Math.min(v1.length, v2.length);
    correlationMatrix[c1][c2] = pearson(v1.slice(0, len), v2.slice(0, len));
  }
}
return [{ json: { descriptiveStats: descriptiveStats, correlationMatrix: correlationMatrix, cleanedRows: cleanedRows, columnRenameMap: d.columnRenameMap, outlierReport: d.outlierReport, numericCols: numericCols, categoricalCols: d.categoricalCols, datetimeCols: d.datetimeCols, profile: d.profile, nRows: d.nRows, nCols: d.nCols, duplicateCount: d.duplicateCount } }];

const vf = $('Validate File').first().json;
const stats = $input.first().json;
return [{
  json: {
    datasetId: vf.datasetId,
    filename: vf.filename,
    nRows: stats.nRows,
    nCols: stats.nCols,
    duplicateCount: stats.duplicateCount,
    numericCols: stats.numericCols,
    categoricalCols: stats.categoricalCols,
    datetimeCols: stats.datetimeCols,
    profile: stats.profile,
    outlierReport: stats.outlierReport,
    descriptiveStats: stats.descriptiveStats,
    correlationMatrix: stats.correlationMatrix,
    cleanedRows: stats.cleanedRows
  }
}];

const recNode = $('Recommend Chart').first().json;
const chartData = (recNode && recNode.output) ? recNode.output : { chartType: 'bar', xField: 'category', yField: 'value', reason: 'default fallback' };
const cleanedRows = $('Build Analysis Payload').first().json.cleanedRows || [];
const xField = chartData.xField || 'category';
const yField = chartData.yField || 'value';
const labels = cleanedRows.slice(0, 10).map(function(r) { return String(r[xField] !== undefined ? r[xField] : 'N/A'); });
const vals = cleanedRows.slice(0, 10).map(function(r) { return parseFloat(r[yField]) || 0; });
const config = {
  type: chartData.chartType || 'bar',
  data: { labels: labels, datasets: [{ label: yField, data: vals }] }
};
const chartUrl = 'https://quickchart.io/chart?c=' + encodeURIComponent(JSON.stringify(config));
return [{ json: { chartUrl: chartUrl, chartType: chartData.chartType || 'bar', xField: xField, yField: yField, reason: chartData.reason || 'auto-selected' } }];

const p = $('Build Analysis Payload').first().json;
const insightsNode = $('Generate Insights').first().json;
const insights = (insightsNode && insightsNode.output)
  ? insightsNode.output
  : { keyInsights: ['AI analysis unavailable - review raw statistics'], businessRecommendations: ['Review the descriptive statistics below'], conclusion: 'AI temporarily unavailable.' };
const chart = $input.first().json;
const statsLines = Object.entries(p.descriptiveStats || {}).map(function(e) {
  const col = e[0]; const s = e[1];
  return '| ' + col + ' | ' + s.min + ' | ' + s.max + ' | ' + s.mean + ' | ' + s.median + ' | ' + s.std + ' |';
}).join('\n');
const corrLines = Object.entries(p.correlationMatrix || {}).map(function(e) {
  const c1 = e[0]; const row = e[1];
  return '| ' + c1 + ' | ' + Object.values(row).join(' | ') + ' |';
}).join('\n');
const outlierLines = Object.entries(p.outlierReport || {}).map(function(e) {
  const col = e[0]; const o = e[1];
  return '- **' + col + '**: ' + o.outlierCount + ' outliers (fences: [' + Number(o.lowerFence).toFixed(2) + ', ' + Number(o.upperFence).toFixed(2) + '])';
}).join('\n');
const ki = (insights.keyInsights || []).map(function(k, i) { return (i + 1) + '. ' + k; }).join('\n');
const br = (insights.businessRecommendations || []).map(function(r, i) { return (i + 1) + '. ' + r; }).join('\n');
const md = '# Data Analysis Report\n\n'
  + '## Dataset Overview\n'
  + '- **File**: ' + p.filename + '\n'
  + '- **Rows**: ' + p.nRows + '\n'
  + '- **Columns**: ' + p.nCols + '\n'
  + '- **Dataset ID**: ' + p.datasetId + '\n\n'
  + '## Data Quality Summary\n'
  + '- Duplicate rows detected: ' + p.duplicateCount + '\n'
  + '- Numeric columns: ' + (p.numericCols || []).join(', ') + '\n'
  + '- Categorical columns: ' + (p.categoricalCols || []).join(', ') + '\n'
  + '- Datetime columns: ' + (p.datetimeCols || []).join(', ') + '\n\n'
  + '## Outliers\n'
  + (outlierLines || 'None detected') + '\n\n'
  + '## Exploratory Data Analysis\n'
  + '| Column | Min | Max | Mean | Median | Std |\n'
  + '|--------|-----|-----|------|--------|-----|\n'
  + (statsLines || '| No numeric columns | - | - | - | - | - |') + '\n\n'
  + '## Correlations\n'
  + (corrLines || 'No numeric columns for correlation') + '\n\n'
  + '## Key Insights\n'
  + ki + '\n\n'
  + '## Business Recommendations\n'
  + br + '\n\n'
  + '## Conclusion\n'
  + (insights.conclusion || '') + '\n\n'
  + '## Suggested Visualization\n'
  + '![Chart](' + chart.chartUrl + ')\n'
  + '- Type: ' + chart.chartType + ', X: ' + chart.xField + ', Y: ' + chart.yField + '\n';
return [{ json: { reportMarkdown: md, chartUrl: chart.chartUrl, datasetId: p.datasetId, summary: { nRows: p.nRows, nCols: p.nCols, numericCols: p.numericCols, categoricalCols: p.categoricalCols, duplicateCount: p.duplicateCount } } }];
